--
-- Table structure for table `setmeal`
--

DROP TABLE IF EXISTS `setmeal`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `setmeal` (
  `id` bigint NOT NULL COMMENT '涓婚敭',
  `category_id` bigint NOT NULL COMMENT '鑿滃搧鍒嗙被id',
  `name` varchar(64) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin NOT NULL COMMENT '濂楅?鍚嶇О',
  `price` decimal(10,2) NOT NULL COMMENT '濂楅?浠锋牸',
  `status` int DEFAULT NULL COMMENT '鐘舵? 0:鍋滅敤 1:鍚?敤',
  `code` varchar(32) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL COMMENT '缂栫爜',
  `description` varchar(512) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL COMMENT '鎻忚堪淇℃伅',
  `image` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL COMMENT '鍥剧墖',
  `create_time` datetime NOT NULL COMMENT '鍒涘缓鏃堕棿',
  `update_time` datetime NOT NULL COMMENT '鏇存柊鏃堕棿',
  `create_user` bigint NOT NULL COMMENT '鍒涘缓浜',
  `update_user` bigint NOT NULL COMMENT '淇?敼浜',
  `is_deleted` int NOT NULL DEFAULT '0' COMMENT '鏄?惁鍒犻櫎',
  PRIMARY KEY (`id`) USING BTREE,
